INSERT INTO "parole" (sujet, savant, texte_arabe, texte_francais, phonétique, explication, tag)
SELECT 'La demande d’intercession au prophète', 'Les Malikites', '« يا أبا عبد الله، أستقبل القبلة ، وأدعو أم أستقبل رسول الله – صلى الله عليه وسلم – ؟', '', '', 'Dans son livre Ach-Chifâ (page 288 et 289 de cette édition) Al-Qâdî ‘Iyâd rapporte que le Calife Aboû Ja’far Al-Mansoûr lorsqu’il a effectué le pèlerinage et a visité la tombe du Prophète (صلى الله عليه وسلم), il a interrogé l’Imâm Mâlik en lui disant :', 'abou ja3far al-mansour, allah, aqida, book'
