INSERT INTO "parole" (sujet, savant, texte_arabe, texte_francais, phonétique, explication, tag)
SELECT 'L’Imâm Ibn Al-Jawzi rapporte que l’Imâm Ahmad Ibn Hanbal n’a jamais attribué de direction à Allâh', 'Ibn Al-Jawzi', 'كان أحمد – يعني الإمام أحمد بن حنبل – لا يقول بالجهة للباري', 'Ahmad (C’est-à-dire l’Imâm Ahmad Ibnou Hanbal) n’a jamais attribué de direction à Al-Bârî (Le Créateur : c’est-à-dire Allâh)', '', 'Dans son livre « Daf’ou Choubahi t-Tachbîh » (page 135 de cette édition) l’Imâm Ibnou Al-Jawzi rapporte :
Informations utiles :
– L’Illustre savant du salaf, le Moujtahid (jurisconsulte), l’Imâm Aboû ‘Abdi l-Lâh Ahmad Ibnou Mouhammad Ibnou Hanbal Ach-Chaybâni est né en 164 à Baghdâd et il est décédé en 241 de l’Hégire à Baghdâd (رحمه الله) c’est-à-dire il y a plus de 1190 ans. Il est l’Imâm de l’école Hanbalite, l’un des quatre Imams.
– L’Imâm, le Hâfidh (spécialiste des chaînes de transmission du hadîth), le Moufassir (exégète) Abdou r-Rahmân Ibnou ‘Ali connu sous le nom de Ibnou l-Jawzi le Hanbalite, est né en 508 à Baghdâd et il est décédé en 597 de l’Hégire à Baghdâd (رحمه الله) c’est-à-dire il y a 835 ans.
– Ibnou l-Jawzi fait partie des piliers des hanbalites. Il a écrit son livre « Daf’ou Choubahi t-Tachbîh » pour répliquer à ceux qui ont attribué le corps à Allâh tout en se réclamant de l’école de l’Imâm Ahmad alors que l’Imâm Ahmad est innocent de ce qu’ils ont pris pour croyance. Ibnou Al- Jawzi a souligné dans ce livre que la croyance du Salaf est bien la croyance de l’Imâm Ahmad, l’exemption de Allâh de l’endroit, de la limite, du corps, de la position debout, assise, de l’installation et de toutes les autres caractéristiques des choses qui entrent en existence et des corps.
– Ici il confirme que contrairement aux mensonges proférés par les anthropomorphistes (moujassimah), l’Imâm Ahmad Ibnou Hanbal n’a jamais attribué de direction à Allâh ta’âlâ.
– Nombreux sont les savants qui ont innocenté l’Imâm Ahmad de cette croyance laide. En plus de l’Imâm Ibnou l-Jawzi, nous pouvons citer le Qâdî Badrou d-Dîn Ibnou Jamâ’ah (رحمه الله) [ Retrouvez la citation : ici ], l’Imâm Ibnou Hajar Al-Haytami (رحمه الله) et d’autres.
– Le Hâfidh Taqiyyou d-Dîn Ibnou Salâh (m.643 H.) a dit : « Allâh a éprouvé deux imams à travers leurs compagnons, alors qu’ils sont innocents [de leurs égarements] : Ahmad Ibnou Hambal a été éprouvé par les moujassimah (anthropomorphistes) et Ja’far As-Sâdiq a été éprouvé par les râfidah (groupe chiite) » [rapporté par Tâjou d-Dîn As-Soubki dans Tabaqâtou ch-Châfi’iyyah Al-Koubrâ]
– L’Imâm Ibnou Châhîn (m. 385 H.) a dit : « Deux hommes vertueux ont été éprouvés par leurs compagnons pervers : Ja’far Ibnou Mouhammad (As-Sâdiq) et Ahmad Ibnou Hambal » [rapporté par Ibnou ‘Açâkir dans Tabyînou kadhibi l-Mouftarî]
– En revanche il a été rapporté de la part de l’Imâm Ahmad qu’il niait le corps au sujet de Allâh [ voir : ici ], et qu’il considérait mécréant ceux qui ont pris pour croyance que Allâh serait un corps ou qu’Il serait dans une direction [ voir : ici ] et [ voir : ici ].
– L’Imâm Ahmad Ibn Hambal a dit : « Devient mécréant celui qui fait ressembler Allâh à Sa créature » [ Rapporté par Ibn Hamdân Al-Hambali dans Nihâyatou l-Moubtadi-în ]', 'ahmad, ahmed, allah, aqida'
WHERE NOT EXISTS (SELECT 1 FROM "parole" WHERE texte_arabe = 'كان أحمد – يعني الإمام أحمد بن حنبل – لا يقول بالجهة للباري');

-- source: https://islamsunnite.net/le-chaykh-al-baydawi-dit-que-le-nouzoul-de-allah-nest-pas-un-deplacement-et-que-allah-est-exempt-du-corps-et-de-la-localisation/
INSERT INTO "parole" (sujet, savant, texte_arabe, texte_francais, phonétique, explication, tag)
SELECT 'Le Chaykh Al-Baydâwi dit que le nouzoûl de Allâh n’est pas un déplacement, et que Allâh est exempt du corps et de la localisation', 'Baydawi', 'وقال البيضاوي : لـما ثبت بالقواطع أنه سبحانه منـزه عن الجسمية والتحيز امتنع عليه النـزول على معنى الانتقال من موضعٍ إلى موضعٍ أخفض منه', '« Al-Baydâwi a dit : Puisqu’il a été confirmé par les preuves catégoriques que Allâh soubhânahou est exempt du corps et de la localisation, il Lui est impossible le nouzoûl dans le sens d’un déplacement d’un endroit vers un endroit qui lui serait inférieur ».', '', 'Dans son commentaire du Sahîh de Al-Boukhâri «Fath Al-Bârî » (tome 3 page 31 de cette édition), l’Imâm Ibnou Hajar Al-‘Asqalâni a dit :
Informations utiles :
– Le Chaykh ‘Abdou l-Lâh Ibnou ‘Oumar Ibnou Mouhammad Ach-Chîrâzi Al-Baydâwi est décédé en 685 de l’Hégire (رحمه الله) c’est-à-dire il y a environ 750 ans. (Certains ont dit qu’il est décédé en 691 de l’Hégire). Il était du madh-hab (Ecole de jurisprudence) de l’Imâm Ach-Châfi’i.
– Littéralement le terme « nouzoûl » signifie « descente », mais l’Imâm Al-Baydâwi (en accord avec les autres savants sunnites) dit qu’au sujet de Allâh le terme « nouzoûl » n’a pas ce sens. Et, il dit également que Allâh est exempt du corps et de la localisation.
– Voir d’autres paroles de savants au sujet du Hadîth An-Nouzoûl : ici .
– Chaykhou l-Islâm, Amîr al-Mouminîn fi l-hadîth (le Prince des croyants dans la science du hadîth) Chihâb ad-Dîn Abou l-Fadl Ahmad Ibnou ‘Ali Ibnou Hajar Al-‘Asqalâni est né en 773 et il est décédé en 852 de l’hégire (رحمه الله) c’est-à-dire il y a plus de 590 ans. C’est un très grand spécialiste de la science du hadîth qui a écrit de nombreux ouvrages. Il est du madh-hab (Ecole de jurisprudence) de l’Imam Ach-Châfi’i. Son livre « Fath Al-Bârî » est incontournable, c’est le plus célèbre commentaire du Sahîh Al-Boukhâri. Consultez sa biographie : ici .
– Cette parole de Al-Baydâwi a également été rapportée par le Chaykh Mouhammad Ibnou ‘Abdi l-Bâqî Az-Zourqâni (certains disent : Az-Zarqâni) Al-Mâliki (رحمه الله) dans son commentaire du Mouwatta de l’Imâm Mâlik. Voir l’article à ce sujet : ici .', 'al asqalani, al-3asqalani, allah, aqida'
WHERE NOT EXISTS (SELECT 1 FROM "parole" WHERE texte_arabe = 'وقال البيضاوي : لـما ثبت بالقواطع أنه سبحانه منـزه عن الجسمية والتحيز امتنع عليه النـزول على معنى الانتقال من موضعٍ إلى موضعٍ أخفض منه');

-- source: https://islamsunnite.net/le-hafidh-al-karmani-dit-que-la-parole-fi-s-sama-ne-doit-pas-etre-prise-au-sens-apparent-et-que-allah-est-sans-endroit/
INSERT INTO "parole" (sujet, savant, texte_arabe, texte_francais, phonétique, explication, tag)
SELECT 'Le Hâfidh Al-Karmâni dit que la parole « fi s-samâ  » ne doit pas être prise au sens apparent, et que Allâh est sans endroit', 'Karmani', '« قوله « في السماء » ظاهره غير مراد، إذ الله منـزه عن الحلول في الـمكان، لكن لما كانت جهة العلو أشرف من غيرها أضافها إليه إشارة إلى علو الذات والصفات »', '« Le sens apparent de Sa parole (fi s-samâ) n’est pas le sens qui est visé car Allâh est exempt de l’incarnation dans un endroit et comme la direction du haut est une direction plus honorable que les autres directions, cela est une attribution qui indique l’exemption de toutes imperfections de l’Être et des attributs ».', '', 'Dans son commentaire du Sahîh de Al-Boukhâri «Fath Al-Bârî » (tome 13 p 412 de cette édition), lors de l’explication du Hadîth dans lequel Zaynab Bintou Jahch (l’épouse du Prophète) a dit : « إن الله أنكحنى في السماء », l’Imâm Ibnou Hajar Al-‘Asqâlani rapporte que le Hâfidh Al-Karmâni a dit :
Informations utiles :
– Le Chaykh, le Hâfidh (spécialiste de la science du Hadîth) Chamsou d-Dîn Mouhammad Ibnou Yoûçouf connu sous le nom de Al-Karmâni Al Baghdâdi est né en 717 et il est décédé en 786 de l’Hégire (رحمه الله) c’est-à-dire il y a environ 650 ans. Il est l’un des commentateurs du Sahîh de Al-Boukhâri.
– Le sens apparent de la parole « fi s-samâ » signifie «dans le ciel» ou «au-dessus du ciel», mais le Hâfidh Al-Karmâni dit bien que ce n’est pas le sens apparent qui est visé dans ce hadîth, car Allâh n’est pas dans un endroit.
– Le sens de la parole de Zaynab « إن الله أنكحنى في السماه » est que Allâh l’a donné en mariage, et que ce mariage est cité dans le Qour-ân (dans le verset 37 de Sourat Al-Ahzâb), car c’est du ciel que descend la révélation. De plus il existe une autre version de ce hadîth qui confirme cette explication, qui est rapporté par At-Tabari, As-Souyoûti, At-Tirmidhi et d’autres dans lequel Zaynab a dit « أنا الذي نزل تزويجي » ce qui a pour sens : « Je suis celle dont le mariage a été révélé ».
– Chaykhou l-Islâm, Amîr al-Mouminîn fi l-hadîth (le Prince des croyants dans la science du hadîth) Chihâb ad-Dîn Abou l-Fadl Ahmad Ibnou ‘Ali Ibnou Hajar Al-‘Asqalâni est né en 773 et il est décédé en 852 de l’hégire (رحمه الله) c’est-à-dire il y a plus de 590 ans. C’est un très grand spécialiste de la science du hadîth qui a écrit de nombreux ouvrages. Il est du madh-hab (Ecole de jurisprudence) de l’Imam Ach-Châfi’i. Son livre « Fath Al-Bârî » est incontournable, c’est le plus célèbre commentaire du Sahîh Al-Boukhâri. Consultez sa biographie : ici .', 'allah, aqida, asqalani, book'
WHERE NOT EXISTS (SELECT 1 FROM "parole" WHERE texte_arabe = '« قوله « في السماء » ظاهره غير مراد، إذ الله منـزه عن الحلول في الـمكان، لكن لما كانت جهة العلو أشرف من غيرها أضافها إليه إشارة إلى علو الذات والصفات »');

