INSERT INTO "parole" (sujet, savant, texte_arabe, texte_francais, phonétique, explication, tag)
SELECT 'L’Imâm Zaynou l-‘Âbidîn dit que Allâh est sans endroit et qu’Il n’est pas limité', 'Les Hanafites', 'أنت اللهُ الذي لاَ تُحَدُّ فَتـكُونَ مـحدوداً', 'C’est Toi Allâh Qui est exempt des limites et Qui n’est donc pas limité', '', 'Informations utiles :
– L’Illustre successeur des compagnons, l’Imâm Zaynou l-‘Âbidîn ‘Ali fils de Al-Houçayn fils de ‘Ali Ibnou Abî Tâlib, que Allâh les agrée tous, est décédé en 94 de l’Hégire (رحمه الله) c’est-à-dire il y a environ 1340 ans. Il est l’arrière petit fils du Messager de Allâh (صلى الله عليه وسلم). Il était surnommé « As-sajjâd » en raison des nombreuses prières surérogatoires qu’il effectuait.
– Ici l’Imâm Zaynou l-‘Âbidîn dit que Allâh n’est pas dans un endroit et qu’Il est exempt des limites. Voici la croyance des musulmans de toute époques et de tout lieux, la croyance des savants du Salaf, la croyance des gens de la famille du Messager de Allâh (صلى الله عليه وسلم).
– Selon les savants, al-mahdoûd (ce qui est limité), c’est ce qui occupe un espace, qu’il soit grand ou petit, qu’il soit palpable comme l’homme ou l’arbre, ou impalpable comme la lumière ou l’obscurité. Et les savants ont dit que ce qui est limité a besoin de qui l’a limité par cette limite-là. Or il n’est pas possible que ce qui est limité se soit limité lui-même selon la limite qu’il aurait, car cela signifierait qu’il se serait créé et cela est impossible, car ce qui existe ne se crée pas soi-même.
– Ces paroles sont rapportées par le Hâfidh –mémorisateur des chaînes de transmission du hadîth–, le Loughawi –spécialiste de la langue–, le Faqîh – spécialiste de jurisprudence–, Mouhammad Mourtadâ Az-Zabîdi Al-Houcayni Al-Hanafi mort en 1205 de l’Hégire (رحمه الله), avec une chaîne de transmission sûre et ininterrompu de lui jusqu’à Zaynou l-‘Âbidîn.', 'ahlou bayt, allah, allah est sans endroit / sans direction, aqida'
WHERE NOT EXISTS (SELECT 1 FROM "parole" WHERE texte_arabe = 'أنت اللهُ الذي لاَ تُحَدُّ فَتـكُونَ مـحدوداً');

-- source: https://islamsunnite.net/limam-ach-chafi3i-explique-les-differentes-sortes-dinnovations-rapporte-par-abou-nou3aym/
INSERT INTO "parole" (sujet, savant, texte_arabe, texte_francais, phonétique, explication, tag)
SELECT 'L’Imâm Ach-Châfi’i explique les différentes sortes d’innovations (rapporté par Aboû Nou’aym)', 'Abou Nou''aym', 'البدعة بدعتان : بدعة محمودة ، وبدعة مذمومة ، فما وافق السنة فهو محمود ، وما خالف السنة فهو مذموم . واحتج بقول عمر بن الخطاب في قيام رمضان : نعمت البدعة هي', 'L’innovation est de deux sortes : l’innovation louable et l’innovation blâmable. Celle qui est conforme à la Sounnah c’est celle qui est louable, et celle qui contredit la Sounnah c’est celle qui est blâmable. Et pour preuve la parole de ‘Oumar Ibnou l-Khattâb lors des prières de nuit durant Ramadân : Quelle bonne innovation', '', 'Le Hâfidh Aboû Nou’aym a rapporté avec sa chaîne de transmission dans son livre « Hilyatou l-Awliyâ» (tome 9, page 121 de cette édition) que l’Imâm Ach-Châfi’i (رحمه الله) a dit:
Information utiles :
– Le Chaykh, l’Imâm, le Hâfidh (spécialiste de la science du hadîth) Aboû Nou’aym Ahmad Ibnou ‘Abdou l-Lâh Al-Isfahâni Ach-Châfi’i est né en 336 et il est décédé en 430 de l’hégire (رحمه الله) c’est-à-dire il y a plus de 1000 ans.
Le Hâfidh Ibnou ‘Açâkir a dit à son sujet : « Le Chaykh, l’Imâm Aboû Nou’aym, le Hâfidh (spécialiste de la science de hadîth), il était unique à son époque par son mérite et sa connaissance, il a composé des ouvrages célèbres comme Hilyatou l-Awliyâ et Tabaqatou l-Asfiyâ, et autres que ceux là, comme de nombreux livres concernant les différentes sortes de science du hadîth» [Tabyînou kadhibi l-Mouftarî]
– L’Imâm, le Moujtahid –jurisconsulte– Mouhammad Ibnou Idrîs Ach-Châfi’i est l’un des plus grands savants de notre communauté, c’est une référence incontournable pour tout musulman. C’est un salaf (C’est à dire qu’il a vécu dans les trois premiers siècles de l’hégire), il est né en 150 et il est décédé en 204 de l’Hégire (رحمه الله) c’est-à-dire il y a environ 1230 ans. Il est l’Imâm de l’école (madh-hab) chafi’ite. Il suffit comme éloge à son sujet que les savants du hadîth ont été en accord pour dire que l’Imâm Ach-Châfi’i est celui qui est visé par la parole du Prophète (صلى الله عليه وسلم) :', 'abou nouaym, allah, aqida, ash-shâfi''î'
WHERE NOT EXISTS (SELECT 1 FROM "parole" WHERE texte_arabe = 'البدعة بدعتان : بدعة محمودة ، وبدعة مذمومة ، فما وافق السنة فهو محمود ، وما خالف السنة فهو مذموم . واحتج بقول عمر بن الخطاب في قيام رمضان : نعمت البدعة هي');

